mapper.sql:
select distinct x.did from (
    select cast(upd.dept_id as unsigned) as did
    from sb_user_permission_dept upd
    where upd.user_id = #{params.scopeDeptUserId}
      and ifnull(upd.del_flag, '0') = '0'

      and upd.customer_id = #{params.scopeDeptCustomerId}

    union
    select ud.department_id as did
    from sys_user_department ud
    where ud.user_id = #{params.scopeDeptUserId}
      and (ud.status = 0 or ud.status = '0' or ud.status is null)
) x
where x.did is not null

sql.if:
and not exists (
    select 1
    from purchase_plan_entry_dep_apply r
    inner join purchase_plan_entry pe on r.purchase_plan_entry_id = pe.id
        and pe.tenant_id = #{scopedTenantId}
        and (pe.del_flag = '0' or pe.del_flag is null)
    inner join purchase_plan pp on pe.parent_id = pp.id
        and pp.tenant_id = #{scopedTenantId}
        and (pp.del_flag = '0' or pp.del_flag is null)
    left join dep_purchase_apply_entry e on r.dep_purchase_apply_entry_id = e.id
        and e.tenant_id = #{scopedTenantId}
        and (e.del_flag is null or e.del_flag != 1)
    where (r.del_flag = '0' or r.del_flag is null)
      and r.tenant_id = #{scopedTenantId}
      and (
          r.dep_purchase_apply_id = dpa.id
          or e.parent_id = dpa.id
      )

          and pp.id != #{excludeReferencedPlanId}

)

